import{c as e,Q as a,j as p,m as i}from"./chunks/framework.mmTo2oFH.js";const m=JSON.parse('{"title":"2025年对自己的总结","description":"","frontmatter":{"title":"2025年对自己的总结","category":"人性洞察","excerpt":"2025 年的我: 这一年，我用一次从减肥到增肌的转变，完成了对自身生命底色的重写，也由此真正看清了底层能力建设的逻辑。 我逐渐意识到，真正可靠的改变，从来不是依赖某一次状态或爆发，而是建立了一套可以长期兑现结果的能力系统。 身体的变化，…","cover":"/media/images/covers/cognition-insight-014-2025年对自己的总结.jpg"},"headers":[],"relativePath":"cognition/insight/014-2025年对自己的总结.md","filePath":"cognition/insight/014-2025年对自己的总结.md","lastUpdated":1780238723000}'),o={name:"cognition/insight/014-2025年对自己的总结.md"};function n(_,t,r,s,c,d){return a(),p("div",null,[...t[0]||(t[0]=[i('<h1 id="_2025年对自己的总结" tabindex="-1">2025年对自己的总结 <a class="header-anchor" href="#_2025年对自己的总结" aria-label="Permalink to &quot;2025年对自己的总结&quot;">​</a></h1><p>2025 年的我: 这一年，我用一次从减肥到增肌的转变，完成了对自身生命底色的重写，也由此真正看清了底层能力建设的逻辑。</p><p>我逐渐意识到，真正可靠的改变，从来不是依赖某一次状态或爆发，而是建立了一套可以长期兑现结果的能力系统。</p><p>身体的变化，只是最先给出反馈的部分，它验证的不是方法，而是结构是否成立。</p><p>当目标被拆解为规则，执行被固化为流程，波动被限制在系统之内，结果便不再依赖情绪出现。</p><p>这让我确信：所有可复利的能力，都是被设计出来的，而不是被情绪驱动出来的。</p><p>正因为走过复杂、见过代价，我对判断与执行的边界愈发清晰。</p><p>我不再急于证明，也不再被外界节奏牵引， 而是把重心放在那些可以跨周期、跨场景持续生效的底层能力上。</p><p>因为经历，所以不惧，更显游刃有余。 这不是姿态，而是一种状态。</p><p>不是刻意表现出来的从容，而是长期在复杂环境中打磨出的本能反应。</p><p>当底色已经重写，判断便不再摇摆，行动自然稳定。</p><p>从这里开始，我选择长期主义作为基本立场， 选择向内生长作为核心路径， 并把一切结果，交由时间完成最终验证。</p>',12)])])}const g=e(o,[["render",n]]);export{m as __pageData,g as default};
